// ── Self-Consistency Check ────────────────────────────────────────────────
// Reads verdicts from all 3 LLM runs, tallies votes, applies guardrails.
// All-agree  → confident result
// 2/3 agree  → majority verdict, confidence −0.08 penalty
// No majority → MANUAL_REVIEW (0.30 confidence)

const pair = $('Split In Batches1').first().json;

const VALID_VERDICTS = ['ELIGIBLE', 'INELIGIBLE', 'MANUAL_REVIEW'];
const HEDGE_WORDS    = ['unclear', 'possibly', 'might', 'could be', 'uncertain',
                        'depends', 'perhaps', 'ambiguous', 'not sure', 'cannot confirm'];

function parseResponse(nodeJson) {
  let raw = nodeJson?.choices?.[0]?.message?.content ?? '';
  raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  const start = raw.indexOf('{'), end = raw.lastIndexOf('}');
  if (start === -1 || end === -1) {
    return { verdict: 'MANUAL_REVIEW', confidence: 0.0, reason: 'LLM response could not be parsed' };
  }
  try {
    const clean = raw.substring(start, end + 1).replace(/,\s*([\]\}])/g, '$1');
    return JSON.parse(clean);
  } catch(e) {
    return { verdict: 'MANUAL_REVIEW', confidence: 0.0, reason: `Parse error: ${e.message}` };
  }
}

function applyGuardrails(p) {
  p.confidence = Number.isFinite(Number(p.confidence)) ? Number(p.confidence) : 0.0;
  p.reason     = String(p.reason ?? '').trim() || 'No reason provided by model';

  // Enforce valid verdict enum
  if (!VALID_VERDICTS.includes(p.verdict)) {
    p.verdict    = 'MANUAL_REVIEW';
    p.reason     = `Unknown verdict "${p.verdict}": ${p.reason}`;
    p.confidence = 0.3;
  }

  // Confidence gate
  if (p.confidence < 0.75) {
    p.verdict = 'MANUAL_REVIEW';
    p.reason  = `Confidence ${p.confidence} below threshold 0.75: ${p.reason}`;
  }

  // Hedging language in ELIGIBLE is a red flag
  if (p.verdict === 'ELIGIBLE' && HEDGE_WORDS.some(w => p.reason.toLowerCase().includes(w))) {
    p.verdict    = 'MANUAL_REVIEW';
    p.reason     = `Hedging language detected in ELIGIBLE verdict: ${p.reason}`;
    p.confidence = Math.min(p.confidence, 0.5);
  }

  return p;
}

// Fetch and validate all 3 run results
const r1 = applyGuardrails(parseResponse($('LLM Call 1 (T=0.0)').first().json));
const r2 = applyGuardrails(parseResponse($('LLM Call 2 (T=0.3)').first().json));
const r3 = applyGuardrails(parseResponse($('LLM Call 3 (T=0.5)').first().json));

const verdicts = [r1.verdict, r2.verdict, r3.verdict];

// Tally votes
const tally = {};
for (const v of verdicts) tally[v] = (tally[v] || 0) + 1;

const [[topVerdict, topCount]] = Object.entries(tally).sort((a, b) => b[1] - a[1]);

const allAgree    = topCount === 3;
const hasMajority = topCount >= 2;

// Average confidence of runs that agree with top verdict
const matchingRuns = [r1, r2, r3].filter(r => r.verdict === topVerdict);
const avgConf      = matchingRuns.reduce((s, r) => s + r.confidence, 0) / matchingRuns.length;

// ── No majority: total disagreement → MANUAL_REVIEW ──────────────────────
if (!hasMajority) {
  return [{
    json: {
      ...pair,
      verdict:           'MANUAL_REVIEW',
      reason:            `Self-consistency failed — 3 runs returned [${verdicts.join(', ')}]. No majority found; escalating to manual review.`,
      verdict_confidence: 0.3,
      verdict_method:    'llm_consistency_failed',
      needs_llm:         false,
      consistency_votes: tally,
      decided_at:        new Date().toISOString()
    }
  }];
}

// ── Majority or full consensus ────────────────────────────────────────────
const confidencePenalty = allAgree ? 0 : 0.08;   // Penalise 2/3 agreement
const finalConf         = Math.max(0, avgConf - confidencePenalty);
const bestReason        = matchingRuns[0].reason;

return [{
  json: {
    ...pair,
    verdict: topVerdict,
    reason: allAgree
      ? `[Self-consistent ×3] ${bestReason}`
      : `[Majority 2/3 — confidence −0.08 applied] ${bestReason}`,
    verdict_confidence: finalConf,
    verdict_method:     allAgree ? 'llm_self_consistent' : 'llm_majority_2of3',
    needs_llm:          false,
    consistency_votes:  tally,
    decided_at:         new Date().toISOString()
  }
}];

const items = $input.all();

let criteria = [];
let evidenceList = [];

for (const item of items) {
  const j = item.json;
  if (j.criterion_type) {
    criteria.push(j);
  } else if (j.bidder_id && j.criterion_id) {
    evidenceList.push(j);
  }
}

const uniqueCriteriaMap = {};
for (const c of criteria) {
  const key = c.id || (c.name + '|' + c.section_reference);
  if (!uniqueCriteriaMap[key]) uniqueCriteriaMap[key] = c;
}
criteria = Object.values(uniqueCriteriaMap);

const evidenceMap = {};
for (const e of evidenceList) {
  const key = `${e.bidder_id}__${e.criterion_id}`;
  evidenceMap[key] = e;
}

const bidder_ids = [...new Set(evidenceList.map(e => e.bidder_id))];

const pairs = [];
for (const bidder_id of bidder_ids) {
  for (const criterion of criteria) {
    const key = `${bidder_id}__${criterion.id}`;
    const evidence = evidenceMap[key] || null;

    pairs.push({
      bidder_id,
      criterion_id: criterion.id,
      criterion_name: criterion.name,
      criterion_type: criterion.criterion_type,
      criterion_description: criterion.description ?? criterion.criterion_description ?? null,
      comparison_operator: criterion.comparison_operator ?? null,
      threshold_value: criterion.threshold_value ?? null,
      threshold_unit: criterion.unit ?? criterion.threshold_unit ?? null,
      tender_submission_date: criterion.tender_submission_date ?? null,

      evidence_id: evidence?.id ?? null,
      extracted_value: evidence?.extracted_value ?? null,
      extracted_unit: evidence?.extracted_unit ?? evidence?.unit ?? null,
      quoted_text: evidence?.source_text ?? evidence?.quoted_text ?? null,
      source_page: Array.isArray(evidence?.source_pages)
        ? evidence.source_pages[0]
        : (evidence?.source_page ?? null),
      extracted_confidence: evidence?.confidence ?? evidence?.extracted_confidence ?? null,
      not_found_reason: evidence?.not_found_reason ?? null,

      evidence_missing: !evidence || evidence.extracted_value == null || String(evidence.extracted_value).trim() === ''
    });
  }
}

return pairs.map(p => ({ json: p }));

const p = $input.first().json;

// ── Helpers ──────────────────────────────────────────────────────────────
function makeVerdict(verdict, reason, confidence, method) {
  return {
    ...p,
    verdict,
    reason,
    verdict_confidence: confidence,
    verdict_method: method,
    needs_llm: false,
    decided_at: new Date().toISOString()
  };
}

function toLLM(reason) {
  return [{
    json: {
      ...p,
      verdict: null,
      needs_llm: true,
      llm_reason: reason,
      decided_at: new Date().toISOString()
    }
  }];
}

function toManual(reason = 'No usable evidence found') {
  return [{
    json: makeVerdict('MANUAL_REVIEW', reason, 0.6, 'rule_manual')
  }];
}

// ── Parsing helpers ──────────────────────────────────────────────────────
function normalizeText(val) {
  return String(val ?? '').toLowerCase().trim();
}

function parseNumber(val) {
  if (val === null || val === undefined) return null;

  let s = String(val).toLowerCase().replace(/[,₹\s]/g, '').trim();

  if (/crore/.test(s))    return parseFloat(s) * 10000000;
  if (/lakh/.test(s))     return parseFloat(s) * 100000;
  if (/thousand/.test(s)) return parseFloat(s) * 1000;
  if (/million/.test(s))  return parseFloat(s) * 1000000;

  const n = parseFloat(s);
  return isNaN(n) ? null : n;
}

function extractNumberFromText(text) {
  const m = text.match(/\d+(\.\d+)?/);
  return m ? parseFloat(m[0]) : null;
}

// ── Derived signals (CORE FIX) ───────────────────────────────────────────
const extractionConf = Number(p.extracted_confidence ?? 0);

const textRaw = String(p.quoted_text ?? p.extracted_value ?? '').trim();
const text = normalizeText(textRaw);
const hasText = text.length > 0;

let extracted = parseNumber(p.extracted_value);
if (extracted === null && hasText) {
  extracted = extractNumberFromText(text);
}

const threshold = parseNumber(p.threshold_value);

const hasNumericPair = extracted !== null && threshold !== null;
const hasAnySignal = hasText || extracted !== null;

const type = normalizeText(p.criterion_type);
const name = normalizeText(p.criterion_name);
const unit = s => s ? ' ' + s : '';

// ── Routing gates ────────────────────────────────────────────────────────

// 1. No data at all → manual
if (!hasAnySignal) {
  return toManual();
}

// 2. Low confidence → LLM
if (extractionConf < 0.6) {
  return toLLM(`Low extraction confidence (${extractionConf})`);
}

// ── NUMERIC RULE ─────────────────────────────────────────────────────────
const numericFamilies = ['numeric', 'financial', 'compliance'];

if (hasNumericPair && numericFamilies.includes(type)) {

  const op = normalizeText(p.comparison_operator ?? '');
  let eligible, usedOp;

  if      (op === '<=' || op === 'lte') { eligible = extracted <= threshold; usedOp = '<='; }
  else if (op === '<'  || op === 'lt')  { eligible = extracted <  threshold; usedOp = '<'; }
  else if (op === '>=' || op === 'gte') { eligible = extracted >= threshold; usedOp = '>='; }
  else if (op === '>'  || op === 'gt')  { eligible = extracted >  threshold; usedOp = '>'; }
  else if (op === '='  || op === '==' || op === 'eq') { eligible = extracted === threshold; usedOp = '='; }
  else {
    const isCeiling = /budget|ceiling|price|cost|max|maximum/.test(name);
    eligible = isCeiling ? extracted <= threshold : extracted >= threshold;
    usedOp = isCeiling ? '<= (inferred ceiling)' : '>= (inferred minimum)';
  }

  return [{
    json: makeVerdict(
      eligible ? 'ELIGIBLE' : 'INELIGIBLE',
      `${p.criterion_name}: ${extracted}${unit(p.extracted_unit)} vs ${threshold}${unit(p.threshold_unit)} [${usedOp}]`,
      0.95,
      'rule_numeric'
    )
  }];
}

// ── BOOLEAN RULE ─────────────────────────────────────────────────────────
if (type === 'boolean') {
  const positive = /\b(yes|provided|complied|confirmed|available|included|attached|submitted|present)\b/.test(text);
  const negative = /\b(no|not|without|absent|nil|missing)\b/.test(text);

  if (positive && !negative) {
    return [{ json: makeVerdict('ELIGIBLE', 'Boolean requirement satisfied', 0.9, 'rule_boolean') }];
  }

  if (negative && !positive) {
    return [{ json: makeVerdict('INELIGIBLE', 'Boolean requirement not satisfied', 0.9, 'rule_boolean') }];
  }

  return toLLM('Ambiguous boolean signal');
}

// ── CERTIFICATION RULE ───────────────────────────────────────────────────
if (type === 'certification') {

  const required = normalizeText(
    String(p.threshold_value ?? p.criterion_description ?? p.criterion_name ?? '')
  );

  const certPatterns = (
    required.match(/(?:iso\s*\d{4,5}(?:[-:]\d+)?|cmmi\s*(?:level\s*)?\d)/gi) ?? []
  ).map(c => c.replace(/\s+/g, '').toLowerCase());

  if (certPatterns.length === 0) {
    return toLLM('Could not parse required certifications');
  }

  const missing = certPatterns.filter(cert => !text.includes(cert));

  return [{
    json: makeVerdict(
      missing.length === 0 ? 'ELIGIBLE' : 'INELIGIBLE',
      missing.length === 0
        ? `All certifications present`
        : `Missing certifications: ${missing.join(', ')}`,
      0.9,
      'rule_certification'
    )
  }];
}

// ── TECHNICAL / EXPERIENCE ───────────────────────────────────────────────
if (type === 'technical' || type === 'experience') {

  // if both numeric → evaluate
  if (hasNumericPair) {
    const isCeiling = /max|ceiling|limit/.test(name);
    const eligible = isCeiling ? extracted <= threshold : extracted >= threshold;

    return [{
      json: makeVerdict(
        eligible ? 'ELIGIBLE' : 'INELIGIBLE',
        `Technical numeric: ${extracted} vs ${threshold}`,
        0.85,
        'rule_technical_numeric'
      )
    }];
  }

  // otherwise → LLM
  return toLLM('Technical/experience requires semantic evaluation');
}

// ── DATE ─────────────────────────────────────────────────────────────────
if (type === 'date') {
  return toLLM('Date comparison requires context');
}

// ── TEXT / QUALITATIVE ───────────────────────────────────────────────────
if (type === 'text' || type === 'qualitative') {
  return toLLM('Free-text evaluation required');
}

// ── FALLBACK ─────────────────────────────────────────────────────────────
return toLLM(`No deterministic rule for type: ${type}`);

function uuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

const v = $input.first().json;

let finalVerdict = 'MANUAL_REVIEW';
if (v.verdict === 'ELIGIBLE')       finalVerdict = 'PASS';
else if (v.verdict === 'INELIGIBLE') finalVerdict = 'FAIL';
else if (v.verdict === 'MANUAL_REVIEW') finalVerdict = 'MANUAL_REVIEW';

if (!['PASS', 'FAIL', 'MANUAL_REVIEW'].includes(finalVerdict)) {
  finalVerdict = 'MANUAL_REVIEW';
}

if (!$('Merge1').first().json.tender_id) {
  throw new Error('tender_id is missing before POST');
}

return [{
  json: {
    id:          uuid(),
    tender_id:   $('Merge1').first().json.tender_id,
    bidder_id:   v.bidder_id,
    criterion_id: v.criterion_id,
    evidence_id: v.evidence_id || null,

    verdict:     finalVerdict,
    reason:      v.reason || 'No reason provided',
    confidence:  v.verdict_confidence ?? 0.5,

    decided_by:        v.verdict_method || 'rule_engine',
    consistency_votes: v.consistency_votes ?? null,
    version:           1,
    decided_at:        v.decided_at || new Date().toISOString()
  }
}];

const webhookData = $('Webhook Trigger1').first().json.body;

return [{
  json: {
    tender_id:    webhookData.tender_id,
    bidder_ids:   webhookData.bidder_ids,
    status:       'verdict_engine_complete',
    completed_at: new Date().toISOString()
  }
}];
